// Parse the fact-checker raw output
const raw = $input.item.json.output || '';
const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

let factData;
try {
  factData = JSON.parse(cleaned);
} catch (e) {
  factData = {
    overall_verdict: 'UNVERIFIED',
    confidence_score: 0,
    has_issues: false,
    summary: 'Fact-check could not be parsed. Proceeding with study material generation.',
    claims: [],
    warning_flags: []
  };
}

// Pass through original form data + parsed fact-check result
const formData = $('On form submission').item.json;

return [{
  json: {
    full_name: formData['Full name'],
    email_address: formData['Email address'],
    topic_notes: formData['Topic or lecture notes'],
    output_type: formData['What do you want to generate?'],
    fact_check_raw: raw,
    fact_overall_verdict: factData.overall_verdict,
    fact_confidence_score: factData.confidence_score,
    fact_has_issues: factData.has_issues || false,
    fact_summary: factData.summary,
    fact_claims: JSON.stringify(factData.claims || []),
    fact_warning_flags: JSON.stringify(factData.warning_flags || []),
    fact_data_full: JSON.stringify(factData)
  }
}];

