// ─── Gather inputs ───────────────────────────────────────────────
const studyRaw = $input.item.json.output || '';
const studyCleaned = studyRaw.replace(/<think>[\s\S]*?<\/think>/gi, '').replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

let studyData;
try {
  studyData = JSON.parse(studyCleaned);
} catch (e) {
  studyData = { parse_error: true, raw: studyRaw };
}

// Retrieve fact-check data passed through from Parse Fact-Check Result node
// We access the fact-check node output stored in the previous step's context
const fc = {
  overall_verdict: $('Parse Fact-Check Result').item.json.fact_overall_verdict || 'UNVERIFIED',
  confidence_score: $('Parse Fact-Check Result').item.json.fact_confidence_score || 0,
  has_issues: $('Parse Fact-Check Result').item.json.fact_has_issues || false,
  summary: $('Parse Fact-Check Result').item.json.fact_summary || '',
  claims: JSON.parse($('Parse Fact-Check Result').item.json.fact_claims || '[]'),
  warning_flags: JSON.parse($('Parse Fact-Check Result').item.json.fact_warning_flags || '[]')
};

const formData = $('On form submission').item.json;
const outputType = formData['What do you want to generate?'];

// ─── Verdict style helpers ────────────────────────────────────────
const verdictStyle = {
  TRUE:       { emoji: '✅', label: 'TRUE',       color: '#22C55E' },
  FALSE:      { emoji: '❌', label: 'FALSE',      color: '#EF4444' },
  MISLEADING: { emoji: '⚠️', label: 'MISLEADING', color: '#F59E0B' },
  UNVERIFIED: { emoji: '❓', label: 'UNVERIFIED', color: '#94A3B8' }
};
const vs = verdictStyle[fc.overall_verdict] || verdictStyle['UNVERIFIED'];

// ─── Confidence bar ───────────────────────────────────────────────
const score = fc.confidence_score || 0;
const filled = Math.round(score / 5);
const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);

// ─── Fact-Check claims HTML ───────────────────────────────────────
let claimsHtml = '';
if (Array.isArray(fc.claims) && fc.claims.length > 0) {
  fc.claims.forEach((c, i) => {
    const cvs = verdictStyle[c.verdict] || verdictStyle['UNVERIFIED'];
    const sourcesHtml = Array.isArray(c.sources) && c.sources.length
      ? c.sources.map(s => `<li style="margin:4px 0;color:#94A3B8;font-size:12px;">• ${s}</li>`).join('')
      : '<li style="color:#94A3B8;font-size:12px;">• No sources found</li>';
    claimsHtml += `
      <div style="background:#0F172A;border:1px solid #334155;border-left:4px solid ${cvs.color};border-radius:10px;padding:14px 18px;margin-bottom:10px;">
        <p style="margin:0 0 4px;font-size:11px;color:#94A3B8;text-transform:uppercase;letter-spacing:0.05em;">Claim ${i + 1}</p>
        <p style="margin:0 0 8px;font-size:14px;font-weight:600;color:#F8FAFC;">&ldquo;${c.claim}&rdquo;</p>
        <span style="background:${cvs.color}22;color:${cvs.color};font-size:11px;font-weight:700;padding:2px 8px;border-radius:20px;">${cvs.emoji} ${cvs.label}</span>
        <p style="margin:8px 0 8px;font-size:12px;color:#CBD5E1;line-height:1.5;">${c.explanation}</p>
        <ul style="margin:0;padding:0;list-style:none;">${sourcesHtml}</ul>
      </div>`;
  });
} else {
  claimsHtml = `<p style="font-size:13px;color:#94A3B8;font-style:italic;">No specific factual claims were identified in the input (e.g. it may be a topic name only).</p>`;
}

// ─── Warning flags HTML ───────────────────────────────────────────
let flagsHtml = '';
if (Array.isArray(fc.warning_flags) && fc.warning_flags.length > 0) {
  const items = fc.warning_flags.map(f => `<li style="margin:4px 0;color:#FCA5A5;font-size:13px;">⚑ ${f}</li>`).join('');
  flagsHtml = `<div style="background:#450A0A22;border:1px solid #EF444444;border-radius:10px;padding:14px 18px;">
    <p style="margin:0 0 6px;font-size:11px;color:#F87171;text-transform:uppercase;letter-spacing:0.05em;font-weight:600;">⚑ Warning Flags</p>
    <ul style="margin:0;padding:0;list-style:none;">${items}</ul>
  </div>`;
} else {
  flagsHtml = `<p style="font-size:13px;color:#34D399;">✓ No warning flags detected.</p>`;
}

// ─── Alert banner if issues found ────────────────────────────────
const issueBanner = fc.has_issues
  ? `<div style="background:#451A0322;border:2px solid #F59E0B;border-radius:12px;padding:14px 20px;margin-bottom:20px;">
      <p style="margin:0;font-size:13px;color:#FCD34D;"><strong>⚠️ Accuracy Warning:</strong> One or more claims in your notes were rated FALSE or MISLEADING. The study material below has been annotated with dispute markers. Please verify flagged points with primary sources before memorising.</p>
    </div>`
  : `<div style="background:#052E1622;border:2px solid #22C55E;border-radius:12px;padding:14px 20px;margin-bottom:20px;">
      <p style="margin:0;font-size:13px;color:#86EFAC;"><strong>✅ Content Verified:</strong> No major factual issues were detected in your notes. Your study material is based on verified content.</p>
    </div>`;

// ─── Study material HTML ──────────────────────────────────────────
let studyHtml = '';

function buildFlashcardsHtml(flashcards) {
  if (!Array.isArray(flashcards) || flashcards.length === 0) return '<p style="color:#94A3B8;">No flashcards generated.</p>';
  return flashcards.map((f, i) => `
    <div style="background:#0F172A;border:1px solid #334155;border-radius:10px;padding:14px 18px;margin-bottom:10px;">
      <p style="margin:0 0 6px;font-size:11px;color:#818CF8;text-transform:uppercase;letter-spacing:0.05em;font-weight:600;">Card ${i + 1}</p>
      <p style="margin:0 0 8px;font-size:14px;font-weight:600;color:#F8FAFC;">Q: ${f.question}</p>
      <p style="margin:0;font-size:13px;color:#CBD5E1;line-height:1.5;">A: ${f.answer}</p>
    </div>`).join('');
}

function buildQuizHtml(quiz) {
  if (!Array.isArray(quiz) || quiz.length === 0) return '<p style="color:#94A3B8;">No quiz generated.</p>';
  return quiz.map((q, i) => {
    const optionsHtml = Object.entries(q.options || {}).map(([letter, text]) => {
      const isCorrect = letter === q.correct_answer;
      return `<li style="margin:4px 0;font-size:13px;color:${isCorrect ? '#34D399' : '#CBD5E1'};">${letter}. ${text}${isCorrect ? ' ✓' : ''}</li>`;
    }).join('');
    return `
      <div style="background:#0F172A;border:1px solid #334155;border-radius:10px;padding:14px 18px;margin-bottom:10px;">
        <p style="margin:0 0 8px;font-size:11px;color:#818CF8;text-transform:uppercase;letter-spacing:0.05em;font-weight:600;">Question ${i + 1}</p>
        <p style="margin:0 0 10px;font-size:14px;font-weight:600;color:#F8FAFC;">${q.question}</p>
        <ul style="margin:0;padding:0;list-style:none;">${optionsHtml}</ul>
      </div>`;
  }).join('');
}

function buildSummaryHtml(summary) {
  if (!summary || summary.parse_error) return '<p style="color:#94A3B8;">No summary generated.</p>';
  const conceptsHtml = Array.isArray(summary.key_concepts)
    ? summary.key_concepts.map(c => `<li style="margin:6px 0;"><strong style="color:#A5B4FC;">${c.term}:</strong> <span style="color:#CBD5E1;font-size:13px;">${c.definition}</span></li>`).join('')
    : '';
  const takeawaysHtml = Array.isArray(summary.key_takeaways)
    ? summary.key_takeaways.map(t => `<li style="margin:4px 0;color:#CBD5E1;font-size:13px;">• ${t}</li>`).join('')
    : '';
  return `
    <div style="background:#0F172A;border:1px solid #334155;border-radius:10px;padding:18px 20px;margin-bottom:12px;">
      <p style="margin:0 0 6px;font-size:11px;color:#818CF8;text-transform:uppercase;letter-spacing:0.05em;font-weight:600;">Topic</p>
      <p style="margin:0 0 12px;font-size:18px;font-weight:700;color:#F8FAFC;">${summary.topic || 'N/A'}</p>
      <p style="margin:0 0 4px;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.05em;">Overview</p>
      <p style="margin:0 0 16px;font-size:13px;color:#CBD5E1;line-height:1.6;">${summary.overview || ''}</p>
      <p style="margin:0 0 8px;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.05em;">Key Concepts</p>
      <ul style="margin:0 0 16px;padding:0;list-style:none;">${conceptsHtml}</ul>
      <p style="margin:0 0 8px;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.05em;">Key Takeaways</p>
      <ul style="margin:0;padding:0;list-style:none;">${takeawaysHtml}</ul>
    </div>`;
}

if (outputType === 'Flashcards') {
  studyHtml = `<p style="margin:0 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📇 Flashcards</p>${buildFlashcardsHtml(studyData.flashcards)}`;
} else if (outputType === 'Quiz') {
  studyHtml = `<p style="margin:0 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📝 Quiz</p>${buildQuizHtml(studyData.quiz)}`;
} else if (outputType === 'Summary') {
  studyHtml = `<p style="margin:0 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📖 Summary</p>${buildSummaryHtml(studyData.summary)}`;
} else if (outputType === 'All three') {
  studyHtml = `
    <p style="margin:0 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📖 Summary</p>
    ${buildSummaryHtml(studyData.summary)}
    <p style="margin:20px 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📇 Flashcards</p>
    ${buildFlashcardsHtml(studyData.flashcards)}
    <p style="margin:20px 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">📝 Quiz</p>
    ${buildQuizHtml(studyData.quiz)}`;
}

// ─── Final email HTML ─────────────────────────────────────────────
const html = `
<div style="font-family:'Inter','Segoe UI',Roboto,sans-serif;background:#0F172A;padding:32px 20px;">
  <div style="max-width:640px;margin:0 auto;background:#1E293B;border-radius:24px;overflow:hidden;border:1px solid #334155;">

    <!-- Header -->
    <div style="background:linear-gradient(135deg,#1E1B4B 0%,#312E81 100%);padding:36px 30px;text-align:center;border-bottom:1px solid #818CF833;">
      <span style="display:inline-block;background:rgba(255,255,255,0.1);padding:6px 14px;border-radius:100px;margin-bottom:14px;color:#A5B4FC;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1.5px;">AI Study Assistant + Fact-Checker</span>
      <h1 style="margin:0;color:#fff;font-size:22px;font-weight:700;">Your Verified Study Material</h1>
      <p style="margin:6px 0 0;color:#C7D2FE;font-size:13px;">Fact-checked before generation</p>
    </div>

    <div style="padding:32px 30px;color:#E2E8F0;line-height:1.6;">

      <!-- Issue Banner -->
      ${issueBanner}

      <!-- Fact-Check Section -->
      <p style="margin:0 0 12px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">🔍 Fact-Check Report</p>

      <div style="background:#0F172A;border:2px solid ${vs.color}44;border-radius:14px;padding:20px;text-align:center;margin-bottom:20px;">
        <p style="margin:0 0 4px;font-size:11px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;">Overall Verdict</p>
        <p style="margin:0 0 6px;font-size:28px;">${vs.emoji}</p>
        <p style="margin:0 0 10px;font-size:18px;font-weight:700;color:${vs.color};">${vs.label}</p>
        <p style="margin:0 0 12px;font-size:13px;color:#CBD5E1;max-width:460px;margin-left:auto;margin-right:auto;">${fc.summary}</p>
        <p style="margin:0 0 4px;font-size:12px;color:#64748B;">Confidence: <strong style="color:#F8FAFC;">${score}%</strong></p>
        <p style="margin:0;font-size:12px;color:${vs.color};letter-spacing:1px;font-family:monospace;">${bar}</p>
      </div>

      <p style="margin:0 0 10px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">Claims Analysed</p>
      ${claimsHtml}

      <p style="margin:16px 0 10px;font-size:12px;color:#64748B;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;">Warning Flags</p>
      ${flagsHtml}

      <div style="border-top:1px solid #334155;margin:28px 0;"></div>

      <!-- Study Material Section -->
      ${studyHtml}

      <!-- Disclaimer -->
      <div style="margin-top:24px;padding:14px 16px;background:rgba(129,140,248,0.05);border-left:4px solid #6366F1;border-radius:4px;">
        <p style="margin:0;font-size:12px;color:#C7D2FE;font-style:italic;"><strong>Note:</strong> This report is AI-generated. The fact-check uses real-time web search but is not infallible. Always verify critical claims with primary academic sources.</p>
      </div>
    </div>

    <!-- Footer -->
    <div style="background:#161E2E;padding:16px;text-align:center;font-size:11px;color:#64748B;border-top:1px solid #334155;letter-spacing:0.5px;">
      SENT VIA <strong style="color:#94A3B8;">AI STUDY ASSISTANT + FACT-CHECKER</strong>
    </div>
  </div>
</div>`;

return [{
  json: {
    formatted_html: html,
    study_raw_output: studyRaw,
    fact_overall_verdict: fc.overall_verdict,
    fact_confidence_score: fc.confidence_score,
    fact_has_issues: fc.has_issues,
    fact_summary: fc.summary,
    output_type: outputType,
    student_name: formData['Full name'],
    student_email: formData['Email address'],
    topic_snippet: formData['Topic or lecture notes'].slice(0, 120)
  }
}];

